define(['core/notification'],function(Notification){var PDFJS_URL=M.cfg.wwwroot+'/mod/videoplayer/thirdpartylibs/pdfjs/pdf.min.mjs';var PDFJS_WORKER_URL=M.cfg.wwwroot+'/mod/videoplayer/thirdpartylibs/pdfjs/pdf.worker.min.mjs';var pdfjsPromise=null;var loadPdfJs=function(){if(!pdfjsPromise){pdfjsPromise=import(PDFJS_URL).then(function(pdfjsLib){pdfjsLib.GlobalWorkerOptions.workerSrc=PDFJS_WORKER_URL;return pdfjsLib;});}return pdfjsPromise;};var hide=function(node,value){if(node){node.hidden=value;}};var showError=function(root,error){hide(root.querySelector('.mod-videoplayer-pdfjs-canvas-wrap'),true);hide(root.querySelector('.mod-videoplayer-pdfjs-topbar'),true);hide(root.querySelector('[data-region="pdfjs-loading"]'),true);hide(root.querySelector('[data-region="pdfjs-error"]'),false);if(error&&window.console){window.console.error(error);}};var initViewer=function(root,pdfjsLib){var pdfUrl=root.getAttribute('data-pdf-url');var canvas=root.querySelector('.mod-videoplayer-pdfjs-canvas');var previous=root.querySelector('[data-action="previous-page"]');var next=root.querySelector('[data-action="next-page"]');var zoomIn=root.querySelector('[data-action="zoom-in"]');var zoomOut=root.querySelector('[data-action="zoom-out"]');var currentPageNode=root.querySelector('[data-region="current-page"]');var totalPagesNode=root.querySelector('[data-region="total-pages"]');var loading=root.querySelector('[data-region="pdfjs-loading"]');var wrap=root.querySelector('.mod-videoplayer-pdfjs-canvas-wrap');if(!pdfUrl||!canvas){showError(root);return;}var context=canvas.getContext('2d');var pdfDocument=null,pageNumber=1,scale=1.2,rendering=false,pendingPage=null;var updateButtons=function(){if(!pdfDocument){return;}if(previous){previous.disabled=pageNumber<=1;}if(next){next.disabled=pageNumber>=pdfDocument.numPages;}if(currentPageNode){currentPageNode.textContent=String(pageNumber);}if(totalPagesNode){totalPagesNode.textContent=String(pdfDocument.numPages);}};var prefetch=function(num){if(!pdfDocument||num<1||num>pdfDocument.numPages){return;}pdfDocument.getPage(num).catch(function(){});};var renderPage=function(num){rendering=true;if(canvas){canvas.classList.add('is-rendering');}pdfDocument.getPage(num).then(function(page){var width=wrap?Math.max(wrap.clientWidth-24,320):900;var base=page.getViewport({scale:1});var finalScale=Math.min(scale,width/base.width);var viewport=page.getViewport({scale:finalScale});var outputScale=window.devicePixelRatio||1;canvas.width=Math.floor(viewport.width*outputScale);canvas.height=Math.floor(viewport.height*outputScale);canvas.style.width=Math.floor(viewport.width)+'px';canvas.style.height=Math.floor(viewport.height)+'px';return page.render({canvasContext:context,viewport:viewport,transform:outputScale!==1?[outputScale,0,0,outputScale,0,0]:null}).promise;}).then(function(){rendering=false;hide(loading,true);if(canvas){canvas.classList.remove('is-rendering');}updateButtons();prefetch(pageNumber+1);prefetch(pageNumber-1);if(pendingPage!==null){var nextPage=pendingPage;pendingPage=null;renderPage(nextPage);}}).catch(function(error){rendering=false;Notification.exception(error);showError(root,error);});};var queue=function(num){if(rendering){pendingPage=num;}else{renderPage(num);}};var go=function(num){if(!pdfDocument){return;}pageNumber=Math.max(1,Math.min(pdfDocument.numPages,num));queue(pageNumber);};if(previous){previous.addEventListener('click',function(){go(pageNumber-1);});}if(next){next.addEventListener('click',function(){go(pageNumber+1);});}if(zoomIn){zoomIn.addEventListener('click',function(){scale=Math.min(3,scale+0.15);queue(pageNumber);});}if(zoomOut){zoomOut.addEventListener('click',function(){scale=Math.max(0.5,scale-0.15);queue(pageNumber);});}window.addEventListener('resize',function(){if(pdfDocument){queue(pageNumber);}});hide(loading,false);pdfjsLib.getDocument({url:pdfUrl,withCredentials:true,rangeChunkSize:262144}).promise.then(function(pdf){pdfDocument=pdf;updateButtons();renderPage(pageNumber);}).catch(function(error){Notification.exception(error);showError(root,error);});};var init=function(){var viewers=Array.prototype.slice.call(document.querySelectorAll('.mod-videoplayer-pdfjs-viewer'));if(!viewers.length){return;}loadPdfJs().then(function(pdfjsLib){viewers.forEach(function(root){initViewer(root,pdfjsLib);});}).catch(function(error){Notification.exception(error);viewers.forEach(function(root){showError(root,error);});});};return{init:init};});
